1	// game-of-life.spec.ts
2	import { describe, it, expect } from "vitest";
3	import { nextGeneration } from "./game-of-life.js";
4	
5	describe("Conway's Game of Life - Next Generation", () => {
6	  it("should return empty grid when given empty grid", () => {
7	    expect(nextGeneration([])).toEqual([]);
8	  });
9	  it("should kill a single live cell with 0 neighbors", () => {
10	    expect(nextGeneration([[0, 0]])).toEqual([]);
11	  });
12	  it("should kill two adjacent live cells (each has only 1 neighbor)", () => {
13	    expect(nextGeneration([[0, 1], [1, 1]])).toEqual([]);
14	  });
15	  it("should preserve a 2x2 block (still life - each cell has 3 neighbors)", () => {
16	    const result = nextGeneration([[0, 0], [1, 0], [0, 1], [1, 1]]);
17	    expect(new Set(result.map((c) => (c as number[]).join(",")))).toEqual(
18	      new Set(["0,0", "1,0", "0,1", "1,1"]),
19	    );
20	  });
21	  it("should rotate a vertical blinker into a horizontal blinker", () => {
22	    const result = nextGeneration([[0, 0], [0, 1], [0, 2]]);
23	    expect(new Set(result.map((c) => (c as number[]).join(",")))).toEqual(
24	      new Set(["-1,1", "0,1", "1,1"]),
25	    );
26	  });
27	  it("should bring a dead cell with exactly 3 live neighbors to life", () => {
28	    const result = nextGeneration([[0, 0], [1, 0], [0, 1]]);
29	    expect(new Set(result.map((c) => (c as number[]).join(",")))).toEqual(
30	      new Set(["0,0", "1,0", "0,1", "1,1"]),
31	    );
32	  });
33	  it.todo("should kill a live cell with more than 3 live neighbors (overpopulation)");
34	  it.todo("should support negative coordinates");
35	});
36

1	type Cell = [number, number];
2	
3	const cellKey = (x: number, y: number): string => `${x},${y}`;
4	
5	const neighborOffsets: Cell[] = [
6	  [-1, -1], [-1, 0], [-1, 1],
7	  [0, -1],           [0, 1],
8	  [1, -1],  [1, 0],  [1, 1],
9	];
10	
11	const neighborsOf = (x: number, y: number): Cell[] =>
12	  neighborOffsets.map(([dx, dy]) => [x + dx, y + dy]);
13	
14	const countLiveNeighbors = (x: number, y: number, liveSet: Set<string>): number =>
15	  neighborsOf(x, y).filter(([nx, ny]) => liveSet.has(cellKey(nx, ny))).length;
16	
17	export function nextGeneration(cells: Cell[]): Cell[] {
18	  const liveSet = new Set(cells.map(([x, y]) => cellKey(x, y)));
19	
20	  const candidateMap = new Map<string, Cell>();
21	  for (const [x, y] of cells) {
22	    candidateMap.set(cellKey(x, y), [x, y]);
23	    for (const [nx, ny] of neighborsOf(x, y)) {
24	      candidateMap.set(cellKey(nx, ny), [nx, ny]);
25	    }
26	  }
27	
28	  const result: Cell[] = [];
29	  for (const [key, [x, y]] of candidateMap) {
30	    const neighbors = countLiveNeighbors(x, y, liveSet);
31	    const isAlive = liveSet.has(key);
32	    if (isAlive && (neighbors === 2 || neighbors === 3)) {
33	      result.push([x, y]);
34	    } else if (!isAlive && neighbors === 3) {
35	      result.push([x, y]);
36	    }
37	  }
38	  return result;
39	}
